<span class="line"><span style="color:#E1E4E8;">server.sendmail(</span><span style="color:#9ECBFF;">&quot;xiaoxinxxxx@qq.com&quot;</span><span style="color:#E1E4E8;">,[</span><span style="color:#9ECBFF;">&quot;xinleixxxx@126.com&quot;</span><span style="color:#E1E4E8;">],msg.as_string())</span></span>
